// 加载曝光模式
function loadExposure(deviceIp) {
    // v7.54: 从 function.json 加载曝光模式选项
    if (!deviceFunctionData || !deviceFunctionData.functions || !deviceFunctionData.functions.exposure_mode) {
        console.warn('[Exposure] No function.json data available');
        return;
    }

    var exposureValues = deviceFunctionData.functions.exposure_mode.opt_values;
    if (!exposureValues || !Array.isArray(exposureValues) || exposureValues.length === 0) {
        console.warn('[Exposure] exposure_mode not supported');
        var select = document.getElementById('exposureMode');
        if (select) {
            select.innerHTML = '<option value="">-- 不支持 --</option>';
            select.disabled = true;
        }
        return;
    }

    // 填充选项
    var select = document.getElementById('exposureMode');
    if (select) {
        select.innerHTML = '';
        select.disabled = false;

        exposureValues.forEach(function(p) {
            var opt = document.createElement('option');
            opt.value = p;
            // 中文标签
            var labelMap = {
                'manual': '手动',
                'auto': '自动',
                'IrisFirst': '光圈优先',
                'ShutterFirst': '快门优先'
            };
            opt.textContent = labelMap[p] || p;
            select.appendChild(opt);
        });
    }

    // 获取当前值
    apiGet('/api/v1/ptz/' + deviceIp + '/image/exposure').then(function(r) {
        if (r && r.success && r.data) {
            if (select && r.data.mode) {
                select.value = r.data.mode;
                // 更新快门光圈禁用状态
                updateShutterIrisState();
            }
        }
    }).catch(function(e) {
        console.warn('[Exposure] Load failed:', e);
    });
}

// 设置曝光模式
function setExposureMode(mode) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    // v7.54: 支持多种曝光模式的中文显示
    var labelMap = {
        'manual': '手动',
        'auto': '自动',
        'IrisFirst': '光圈优先',
        'ShutterFirst': '快门优先'
    };
    apiPost('/api/v1/ptz/' + dev + '/image/exposure', { mode: mode })
        .then(function(r) {
            if (r && r.success) {
                showToast('success', '曝光模式: ' + (labelMap[mode] || mode));
                if (typeof operationLog === 'function') operationLog('曝光: ' + (labelMap[mode] || mode), 'success');
            }
        });
    // v5.47: 更新快门光圈禁用状态
    updateShutterIrisState();
}

// v5.47: 更新快门光圈禁用状态
function updateShutterIrisState() {
    // v7.30: 检查设备是否连接
    if (!window.connectedDevice || !window.connectedDevice.ip) {
        // 设备未连接,所有控件保持禁用
        return;
    }

    var exposureMode = document.getElementById('exposureMode');
    var shutterSelect = document.getElementById('shutterSpeed');
    var irisSelect = document.getElementById('irisLevel');
    var gainSlider = document.getElementById('gainLevel');
    if (!exposureMode || !shutterSelect || !irisSelect) return;

    // v7.54: 支持多种曝光模式
    var mode = exposureMode.value;
    var shutterEnabled = (mode === 'manual' || mode === 'ShutterFirst');
    var irisEnabled = (mode === 'manual' || mode === 'IrisFirst');
    var gainEnabled = (mode === 'manual' || mode === 'ShutterFirst' || mode === 'IrisFirst');
    shutterSelect.disabled = !shutterEnabled;
    irisSelect.disabled = !irisEnabled;
    if (gainSlider) gainSlider.disabled = !gainEnabled;

    // v8.40: 自动模式时隐藏快门/光圈/增益
    var shutterRow = shutterSelect.parentElement.parentElement;
    var gainRow = gainSlider ? gainSlider.parentElement : null;
    if (mode === 'auto') {
        shutterRow.style.display = 'none';
        if (gainRow) gainRow.style.display = 'none';
    } else {
        shutterRow.style.display = '';
        if (gainRow) gainRow.style.display = '';
        shutterSelect.style.opacity = shutterEnabled ? '1' : '0.5';
        irisSelect.style.opacity = irisEnabled ? '1' : '0.5';
        if (gainSlider) gainSlider.style.opacity = gainEnabled ? '1' : '0.5';
    }
}

