function loadShutter(deviceIp) {
    // v7.32: 必须有 function.json
    if (!deviceFunctionData || !deviceFunctionData.functions || !deviceFunctionData.functions.shutter) {
        console.warn('[Shutter] No function.json data available');
        return;
    }

    var shutterValues = deviceFunctionData.functions.shutter.opt_values;
    if (!shutterValues || !Array.isArray(shutterValues) || shutterValues.length === 0) {
        console.warn('[Shutter] shutter not supported');
        var shutterSelect = document.getElementById('shutterSpeed');
        if (shutterSelect) {
            shutterSelect.innerHTML = '<option value="">-- 不支持 --</option>';
            shutterSelect.disabled = true;
        }
        return;
    }

    apiGet('/api/v1/ptz/' + deviceIp + '/image/shutter').then(function(r) {
        if (r && r.success && r.data) {
            var sh = r.data;
            deviceImageParams.shutter = sh;

            var shutterSelect = document.getElementById('shutterSpeed');
            if (shutterSelect) {
                shutterSelect.innerHTML = '';
                shutterSelect.disabled = false;

                shutterValues.forEach(function(p) {
                    var opt = document.createElement('option');
                    opt.value = p;
                    opt.textContent = p;
                    if (p === sh.current_level) opt.selected = true;
                    shutterSelect.appendChild(opt);
                });
            }
        }
    }).catch(function(e) {
        console.warn('[Shutter] Load failed:', e);
    });
}

// 加载光圈
function loadIris(deviceIp) {
    // v7.32: 必须有 function.json
    if (!deviceFunctionData || !deviceFunctionData.functions || !deviceFunctionData.functions.iris) {
        console.warn('[Iris] No function.json data available');
        return;
    }

    var irisValues = deviceFunctionData.functions.iris.opt_values;
    if (!irisValues || !Array.isArray(irisValues) || irisValues.length === 0) {
        console.warn('[Iris] iris not supported');
