                                        + ' → R=' + ev.r_avg + ' G=' + ev.g_avg + ' B=' + ev.b_avg
                                        + ' (Δ=' + ev.delta + ')', 'debug');
                                } else if (ev.type === 'focus') {
                                    operationLog('对焦 #' + ev.step + ': ' + ev.stage
                                        + ' ' + ev.action + ' 反差=' + ev.contrast
                                        + ' (' + ev.duration + 's) ' + ev.message, 'debug');
                                } else if (ev.type === 'done') {
                                    if (ev.final_red !== undefined) {
                                        showToast('success', label + '完成 R=' + ev.final_red + ' B=' + ev.final_blue);
                                        operationLog('── ' + label + '完成: R=' + ev.final_red + ' B=' + ev.final_blue + ' (' + ev.total_steps + '步) ──', 'success');
                                        // 刷新主控台白平衡滑动条
                                        var wbRed = document.getElementById('wbRed');
                                        var wbBlue = document.getElementById('wbBlue');
                                        var wbRedVal = document.getElementById('wbRedVal');
                                        var wbBlueVal = document.getElementById('wbBlueVal');
                                        if (wbRed) { wbRed.value = ev.final_red; if (wbRedVal) wbRedVal.textContent = ev.final_red; }
                                        if (wbBlue) { wbBlue.value = ev.final_blue; if (wbBlueVal) wbBlueVal.textContent = ev.final_blue; }
                                    } else {
                                        var rollMsg = ev.rollback_steps ? ' (回滚' + ev.rollback_steps + '步)' : '';
                                        showToast('success', label + '完成 反差=' + ev.final_contrast + rollMsg);
                                        operationLog('── ' + label + '完成: 反差=' + ev.final_contrast + rollMsg + ' (' + ev.total_steps + '步) ──', 'success');
                                    }
                                    // v8.41: 搜索完成后恢复停止按钮为灰色
                                    if (stopBtn) { stopBtn.disabled = true; stopBtn.style.opacity = '0.5'; }
                                    var toggleId = mode === 'whitebalance' ? 'wbTimerToggle' : 'focusTimerToggle'; var toggleEl = document.getElementById(toggleId); if (toggleEl) { toggleEl.checked = false; }
                                } else if (ev.type === 'cleanup') {
                                    operationLog('清理完成', 'info');
                                } else if (ev.type === 'error') {
                                    operationLog(label + '失败: ' + ev.message, 'error');
                                    showToast('error', label + '失败');
                                    // v8.41: 搜索失败后恢复停止按钮为灰色
                                    if (stopBtn) { stopBtn.disabled = true; stopBtn.style.opacity = '0.5'; }
                                    var toggleId = mode === 'whitebalance' ? 'wbTimerToggle' : 'focusTimerToggle'; var toggleEl = document.getElementById(toggleId); if (toggleEl) { toggleEl.checked = false; }
                                } else if (ev.type === 'interrupt') {
                                    // v8.41: 用户停止
                                    operationLog(label + ': ' + ev.message, 'warning');
                                    showToast('warning', label + '已停止');
                                    if (ev.final_red !== undefined) {
                                        var wbRed2 = document.getElementById('wbRed');
                                        var wbBlue2 = document.getElementById('wbBlue');
                                        var wbRedVal2 = document.getElementById('wbRedVal');
                                        var wbBlueVal2 = document.getElementById('wbBlueVal');
                                        if (wbRed2) { wbRed2.value = ev.final_red; if (wbRedVal2) wbRedVal2.textContent = ev.final_red; }
                                        if (wbBlue2) { wbBlue2.value = ev.final_blue; if (wbBlueVal2) wbBlueVal2.textContent = ev.final_blue; }
                                    }
                                    // 恢复停止按钮为灰色
                                    if (stopBtn) { stopBtn.disabled = true; stopBtn.style.opacity = '0.5'; }
                                    var toggleId = mode === 'whitebalance' ? 'wbTimerToggle' : 'focusTimerToggle'; var toggleEl = document.getElementById(toggleId); if (toggleEl) { toggleEl.checked = false; }
                                }
                            } catch(e) { /* 跳过损坏的 JSON */ }
                        }
                        return pump();
                    });
                }
                return pump();
            })
            .catch(function(e) {
                operationLog(label + '异常: ' + e.message, 'error');
                showToast('error', '异常: ' + e.message);
                // v8.41: 恢复停止按钮为灰色
                if (stopBtn) { stopBtn.disabled = true; stopBtn.style.opacity = '0.5'; }
                var toggleId = mode === 'whitebalance' ? 'wbTimerToggle' : 'focusTimerToggle'; var toggleEl = document.getElementById(toggleId); if (toggleEl) { toggleEl.checked = false; }
            })
            .finally(function() {
                // v8.66: 流程结束，统一恢复主控台轮询
                resumePtzPolling();
            });
    }

    function _resetRegionUI() {
        _regionMode = null;
        var btnWB = document.getElementById('btnWbRegionSelect');
        var btnAF = document.getElementById('btnFocusRegionSelect');
        var overlay = document.getElementById('regionOverlay');
        var box = document.getElementById('regionBox');
        if (btnWB) btnWB.className = 'btn btn-secondary btn-sm';
        if (btnAF) btnAF.className = 'btn btn-secondary btn-sm';
        if (overlay) overlay.style.display = 'none';
        if (box) box.style.display = 'none';
    }

    (function() {
        var overlay = document.getElementById('regionOverlay');
        if (!overlay) return;
        var box = document.getElementById('regionBox');
        var isDragging = false;
        overlay.addEventListener('mousedown', function(e) {
            if (!_regionMode) return;
            var pos = _getOverlayPos(e);
            _regionStartX = pos.x; _regionStartY = pos.y;
            box.style.left = pos.x + 'px'; box.style.top = pos.y + 'px';
            box.style.width = '0px'; box.style.height = '0px';
            box.style.display = 'block';
            isDragging = true;
            e.preventDefault();
        });
        overlay.addEventListener('mousemove', function(e) {
            if (!isDragging || !_regionMode) return;
            var pos = _getOverlayPos(e);
            var x = Math.min(_regionStartX, pos.x);
            var y = Math.min(_regionStartY, pos.y);
            var w = Math.abs(pos.x - _regionStartX);
            var h = Math.abs(pos.y - _regionStartY);
            box.style.left = x + 'px'; box.style.top = y + 'px';
            box.style.width = w + 'px'; box.style.height = h + 'px';
        });
        overlay.addEventListener('mouseup', function(e) {
            if (!isDragging || !_regionMode) return;
            isDragging = false;
            _finishRegion();
        });
        overlay.addEventListener('mouseleave', function() {
            if (isDragging) { isDragging = false; _finishRegion(); }
        });
    })();

    </script>
</body>
</html>

