function executeScheduledSearch(mode) {
    var regionStr = localStorage.getItem('region_' + mode);
    if (!regionStr) {
        var modeLabel = mode === 'whitebalance' ? '白平衡' : mode === 'brightness' ? '亮度' : '对焦';
        showToast('warning', modeLabel + '无保存选区');
        return;
    }
    var dev = window.connectedDevice;
    if (!dev || !dev.ip) { showToast('error', '未连接设备'); return; }
    var region = JSON.parse(regionStr);
    var endpoint = mode === 'whitebalance' ? '/api/v1/vision/whitebalance-search'
                 : mode === 'brightness' ? '/api/v1/vision/brightness-search'
                 : '/api/v1/vision/focus-search';
    var label = mode === 'whitebalance' ? '白平衡' : mode === 'brightness' ? '亮度' : '对焦';
    showToast('info', label + '定时执行中...');
    operationLog('── ' + label + '定时执行 ──', 'info');

    // v8.66: 流程开始，暂停主控台轮询
    pausePtzPolling();

    var body;
    if (mode === 'brightness') {
        var target = window.localBrightnessTarget || 50;
        var shutterValues = (deviceFunctionData && deviceFunctionData.functions && deviceFunctionData.functions.shutter) ? deviceFunctionData.functions.shutter.opt_values : [];
        var irisValues = (deviceFunctionData && deviceFunctionData.functions && deviceFunctionData.functions.iris) ? deviceFunctionData.functions.iris.opt_values : [];
        var shutterIdx = 0;
        if (deviceImageParams.shutter && deviceImageParams.shutter.current_level) {
            shutterIdx = shutterValues.indexOf(String(deviceImageParams.shutter.current_level));
            if (shutterIdx < 0) shutterIdx = 0;
        }
        var irisIdx = 0;
        if (deviceImageParams.iris && deviceImageParams.iris.current_level) {
            irisIdx = irisValues.indexOf(String(deviceImageParams.iris.current_level));
            if (irisIdx < 0) irisIdx = 0;
        }
        var gainVal = (deviceImageParams.gain && deviceImageParams.gain.current_level) || 0;
        body = JSON.stringify({
            x: region.x, y: region.y, w: region.w, h: region.h,
            target: target, shutter_idx: shutterIdx, iris_idx: irisIdx,
            gain: gainVal, shutter_values: shutterValues, iris_values: irisValues,
            gain_min: 0, gain_max: (deviceImageParams.gain && deviceImageParams.gain.limit) || 100
        });
    } else {
        body = JSON.stringify({ x: region.x, y: region.y, w: region.w, h: region.h });
    }
    fetch(endpoint, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: body })

